    lmMissionGrowth: 'Crescimento Pessoal',
    lmMissionGrowthDesc: 'Cada missão é uma oportunidade de aprender, crescer e desenvolver habilidades que moldam o caráter e constroem confiança.',
    lmMissionCommunity: 'Construir Comunidade',
    lmMissionCommunityDesc: 'Reunimos voluntários, ONGs e organizações para formar uma rede de apoio unida pela compaixão e ação.',
