  const LINE_CHANNEL_ID = '2009859632'
  const LINE_CHANNEL_SECRET = '111d50fb2a2b977a58343baf44a41f6d'
  const LINE_REDIRECT_URI = 'https://kind-world.up.railway.app'

  const handleLINELogin = () => {
    const state = Math.random().toString(36).substring(2, 18)
    localStorage.setItem('line_oauth_state', state)
    const params = new URLSearchParams({
      response_type: 'code',
      client_id: LINE_CHANNEL_ID,
      redirect_uri: LINE_REDIRECT_URI,
      state,
      scope: 'profile openid email'
    })
    window.location.href = `https://access.line.me/oauth2/v2.1/authorize?${params}`
  }

  const handleLINECallback = async (code: string) => {
    setIsLoading(true)
    window.history.replaceState({}, document.title, '/')
    try {
      const tokenRes = await fetch('/api/line-token', {
        method: 'POST',
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: new URLSearchParams({
          grant_type: 'authorization_code',
          code,
          redirect_uri: LINE_REDIRECT_URI,
          client_id: LINE_CHANNEL_ID,
          client_secret: LINE_CHANNEL_SECRET
        })
      })
      const tokenData = await tokenRes.json()
      if (!tokenData.access_token) {
        throw new Error(tokenData.error_description || tokenData.error || 'Token exchange failed')
      }

      const profileRes = await fetch('/api/line-profile', {
        headers: { Authorization: `Bearer ${tokenData.access_token}` }
      })
      const profile = await profileRes.json()
      if (!profile.userId) throw new Error('Could not fetch LINE profile')

      // Try to extract real email from id_token (requires email scope)
      let lineEmail = `line_${profile.userId}@kindworld.line`
      if (tokenData.id_token) {
        try {
          const payload = JSON.parse(atob(tokenData.id_token.split('.')[1].replace(/-/g, '+').replace(/_/g, '/')))
          if (payload.email) lineEmail = payload.email
        } catch {}
      }
      // Look up by LINE userId first, then by email
      const existingUser = allUsers.find((u: any) =>
        u.lineUserId === profile.userId || u.email === lineEmail
      )

      const userData: User = existingUser ? { ...existingUser } : {
        id: `user_line_${profile.userId}`,
        name: profile.displayName,
        role: 'student',
        hours: 0,
        email: lineEmail,
        avatar: profile.pictureUrl || `https://ui-avatars.com/api/?name=${encodeURIComponent(profile.displayName)}&background=4f46e5&color=fff`,
        joinDate: new Date().toISOString().split('T')[0],
        badges: [],
        userBadges: [],
        completedMissions: 0,
        organizationsHelped: 0,
        rating: 0
      }

      if (!existingUser) {
        setAllUsers((prev: any[]) => [...prev, {
          ...userData,
          password: '',
          status: 'active',
          lineUserId: profile.userId   // internal identifier only — NOT shown as LINE ID
        }])
      } else {
        // Ensure lineUserId is stored for returning LINE users
        setAllUsers((prev: any[]) => prev.map((u: any) =>
          u.email === lineEmail || u.lineUserId === profile.userId
            ? { ...u, lineUserId: profile.userId }
            : u
        ))
      }

      setUser(userData)
      setSelectedRole('student')
      setCurrentPage('dashboard')
      setNotifications(prev => [...prev, `Welcome, ${profile.displayName}! 🎉`])
      // Show region+language setup for new LINE users (or returning users with no language set)
      const savedLanguage = localStorage.getItem('kindworld_language')
      if (!savedLanguage) setShowRegionSetup(true)
    } catch (err: any) {
      const msg = err?.message || 'LINE sign-in failed'
      setNotifications(prev => [...prev, `❌ LINE sign-in failed: ${msg}`])
      setSignInError(`LINE sign-in failed: ${msg}`)
    } finally {
      setIsLoading(false)
    }
  }

  const handleSignIn = () => {
    if (!signInForm.email.trim() || !signInForm.password.trim()) {
      setSignInError(t('pleaseFillAllFields') || 'Please enter your email and password')
      return
    }

    const emailLower = signInForm.email.trim().toLowerCase()

    // Check if trying to log in as admin — only accessible via credentials
    const adminMatch = adminCredentials.find(c => c.email === emailLower)
    if (adminMatch) {
      if (signInForm.password === adminMatch.password) {
        setSignInError('')
        performSignIn('admin')
      } else {
        setSignInError(t('invalidCredentials') || 'Invalid email or password')
      }
      return
    }

    // Check if trying to log in as NGO via credentials
    const ngoMatch = ngoCredentials.find(c => c.email === emailLower)
    if (ngoMatch) {
      if (signInForm.password === ngoMatch.password) {
        setSignInError('')
        performSignIn('ngo')
      } else {
        setSignInError(t('invalidCredentials') || 'Invalid email or password')
      }
      return
    }

    // Check if trying to log in as Sponsor via credentials
    const sponsorMatch = sponsorCredentials.find(c => c.email === emailLower)
    if (sponsorMatch) {
      if (signInForm.password === sponsorMatch.password) {
        setSignInError('')
        performSignIn('sponsor')
      } else {
        setSignInError(t('invalidCredentials') || 'Invalid email or password')
      }
      return
    }

    // Check if email exists in allUsers (real registered user)
    const registeredUser = allUsers.find((u: any) => u.email === emailLower)
    if (!registeredUser) {
      setSignInError('No account found with this email. Please register first.')
      return
    }

    // Check password
    if (registeredUser.password && registeredUser.password !== signInForm.password) {
      setSignInError(t('invalidCredentials') || 'Invalid email or password.')
      return
    }

    // Check role matches
    if (registeredUser.role !== selectedRole) {
      const roleLabel = (r: string) => r === 'student' ? 'Volunteer' : r === 'ngo' ? 'NGO' : r === 'sponsor' ? 'Sponsor' : 'Admin'
      setSignInError(`This account is registered as a ${roleLabel(registeredUser.role)}. Please select "${roleLabel(registeredUser.role)}" above.`)
      return
    }

    setSignInError('')
    setIsLoading(true)
      setTimeout(() => {
        const userData: User = {
          id: registeredUser.id || `user_${Date.now()}`,
          name: registeredUser.name,
          role: registeredUser.role as 'student' | 'ngo' | 'admin' | 'sponsor',
          hours: registeredUser.hours || 0,
          email: registeredUser.email,
          avatar: registeredUser.avatar || `https://ui-avatars.com/api/?name=${encodeURIComponent(registeredUser.name)}&background=4f46e5&color=fff`,
          joinDate: registeredUser.joinDate || new Date().toISOString().split('T')[0],
          badges: registeredUser.userBadges || [],
          userBadges: registeredUser.userBadges || [],
          completedMissions: registeredUser.completedMissions || 0,
          organizationsHelped: registeredUser.organizationsHelped || 0,
          rating: registeredUser.rating || 0,
          companyName: registeredUser.companyName,
          companyIndustry: registeredUser.companyIndustry,
          companyWebsite: registeredUser.companyWebsite,
          sponsorTier: registeredUser.sponsorTier,
          sponsoredMissionIds: registeredUser.sponsoredMissionIds || []
        }
        setUser(userData)
        setSelectedRole(userData.role)
        // Restore sponsorProfile for registered sponsors signing back in
        if (userData.role === 'sponsor') {
          setSponsorProfile(prev => ({
            ...prev,
            companyName: registeredUser.companyName || userData.name,
            industry: registeredUser.companyIndustry || '',
            website: registeredUser.companyWebsite || '',
            tier: (registeredUser.sponsorTier as any) || 'bronze',
            sponsoredMissionIds: registeredUser.sponsoredMissionIds || [],
            contactName: registeredUser.name,
            contactEmail: registeredUser.email
          }))
        }
        // Migrate old missions: fix any missions created by this NGO with a stale organizerId
        if (userData.role === 'ngo') {
          setMissions((prev: Mission[]) => {
            const updated = prev.map(m => {
              if (m.organizer === userData.name && m.organizerId !== userData.email) {
                return { ...m, organizerId: userData.email }
              }
              return m
            })
            localStorage.setItem('kindworld_missions', JSON.stringify(updated))
            return updated
          })
        }
        setIsLoading(false)
        setCurrentPage('dashboard')
        setNotifications([`Welcome back, ${userData.name}! 👋`])
        const savedLanguage = localStorage.getItem('kindworld_language')
        if (!savedLanguage) {
          setShowRegionSetup(true)
        } else {
          const savedRegion = localStorage.getItem('kindworld_user_region')
          if (savedRegion) setUserRegion(savedRegion)
        }
      }, 1000)
  }

